VALUES
  ('dietitian-moex-01733', 'dietitian', 'dietitian-moex-108-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '攝取較多的水溶性膳食纖維可以降低血膽固醇，主要的原因為何？', '["水溶性膳食纖維可以在腸道中吸附膽固醇而排出體外，藉此減少膽固醇的吸收", "水溶性膳食纖維可以抑制肝臟中合成膽固醇的關鍵酵素，藉此降低膽固醇的合成", "水溶性膳食纖維在腸道可與膽汁結合而排出體外，藉此增加肝中膽固醇代謝成膽汁，降低血膽 固醇量", "水溶性膳食纖維吸收後，可降低膽固醇在血中的氧化，藉此降低血膽固醇的堆積"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "35bf5c93d082", "answer_pdf_sha1": "ac94409250aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01734', 'dietitian', 'dietitian-moex-108-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '關於各類脂肪之敘述，下列何者錯誤？', '["食物中的油脂絕大部分為三酸甘油酯（triglyceride）", "卵磷脂（lecithin）為細胞膜主要的磷脂質之一", "皮膚經UV照射，皮下7-dehydrocholesterol可被轉換成維生素D", "卵磷脂（lecithin）及膽固醇主要來自於動物性脂肪，植物性食物則幾乎不含兩者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "35bf5c93d082", "answer_pdf_sha1": "ac94409250aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01735', 'dietitian', 'dietitian-moex-108-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '磷脂質是構成細胞雙重膜的主要成分，下列有關膜特性的敘述，何者錯誤？', '["向細胞內的長鏈由飽和脂肪酸組成", "鹼基具親水性", "膜上兼具疏水性和親水性基團", "親水性基在膜表面，疏水性基面向細胞內"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "35bf5c93d082", "answer_pdf_sha1": "ac94409250aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01736', 'dietitian', 'dietitian-moex-108-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '有關膽固醇的敘述，下列何者錯誤？', '["可由亞麻油酸合成", "為高密度或低密度脂蛋白的組成成分", "動物體內可轉換成膽酸", "在皮膚上經陽光照射可形成維生素D"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "35bf5c93d082", "answer_pdf_sha1": "ac94409250aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01737', 'dietitian', 'dietitian-moex-108-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '臺灣成年人的身體質量指數（BMI）在下列那一個區間，其死亡率相對最低？', '["<18.5", "18.5至<25", "25至<30", "30至<35"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "35bf5c93d082", "answer_pdf_sha1": "ac94409250aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01738', 'dietitian', 'dietitian-moex-108-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關食慾和飽足感的敘述何者正確？', '["咀嚼食物會刺激組織胺（histamine）的分泌，帶來飽足感", "酸性食糜刺激小腸細胞分泌膽囊收縮素（Cholecystokinin，CCK），以產生食慾", "吃飯速度越快越容易產生飽足感", "脂質代謝易促進血清素（serotonin）的分泌，以產生飽足感"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "35bf5c93d082", "answer_pdf_sha1": "ac94409250aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01739', 'dietitian', 'dietitian-moex-108-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '小華因肥胖正以控制熱量的均衡飲食減重，午餐限制在550大卡，則下列何種食物組合最適合？', '["中型高麗菜水煎包2個＋茶葉蛋1個＋芭蕉1根", "低脂鮮奶1杯＋厚片土司2片＋荷包蛋1個＋火腿1片", "五穀飯8分滿1碗＋烤雞腿1隻（2.5兩肉）＋炒青菜半碗＋涼拌小黃瓜1小碟（約100公克） ＋柳丁1顆", "便利商店的鮪魚御飯糰1個＋生菜沙拉1盒"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "35bf5c93d082", "answer_pdf_sha1": "ac94409250aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01740', 'dietitian', 'dietitian-moex-108-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關褐色脂肪組織的敘述，何者錯誤？', '["主要功能為能量儲存", "嬰兒較成人多", "當占嬰兒體重5%時，對產熱調控（thermoregulation）很重要", "含有大量微血管"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "35bf5c93d082", "answer_pdf_sha1": "ac94409250aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01741', 'dietitian', 'dietitian-moex-108-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '有關膽素（choline）的敘述，下列何者錯誤？', '["為B群維生素之一，具有輔酶生化功能性", "人體細胞可內生合成膽素（choline），唯內生量不足以符合個體對膽素的需求量", "葉酸營養不良將增加個體對飲食膽素攝取的需要量", "我國第七版國人膳食營養素參考攝取量已訂定膽素之上限攝取量"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "35bf5c93d082", "answer_pdf_sha1": "ac94409250aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01742', 'dietitian', 'dietitian-moex-108-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '有關葉酸缺乏導致人體紅血球發生病變，下列敘述何者正確？', '["骨髓腔紅血球母細胞異常加速分裂，導致巨核性紅血球生成", "脾臟網狀紅血球細胞停滯分裂，導致巨球性紅血球生成", "肝臟網狀紅血球異常加速分裂，導致巨核性紅血球生成", "骨髓腔紅血球母細胞分裂次數減少，導致巨球性網狀紅血球生成"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:57+00:00", "source_pdf_sha1": "35bf5c93d082", "answer_pdf_sha1": "ac94409250aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "103", "s": "0202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
